from flask import Flask, request, jsonify
from prometheus_client import Counter, Gauge, Histogram, generate_latest, CONTENT_TYPE_LATEST
from functools import wraps
import time
import random

app = Flask(__name__)

request_count = Counter(
    'http_requests_total',
    'Total HTTP requests',
    ['method', 'endpoint', 'status']
)

request_latency = Histogram(
    'http_request_duration_seconds',
    'HTTP request latency',
    ['method', 'endpoint']
)

active_requests = Gauge(
    'http_requests_in_progress',
    'Number of HTTP requests in progress',
    ['method', 'endpoint']
)

business_transactions = Counter(
    'business_transactions_total',
    'Total business transactions',
    ['transaction_type', 'status']
)

business_revenue = Counter(
    'business_revenue_total',
    'Total revenue generated',
    ['currency']
)

active_users = Gauge(
    'active_users',
    'Number of active users'
)

database_connections = Gauge(
    'database_connections',
    'Number of active database connections'
)

cache_hit_rate = Gauge(
    'cache_hit_rate',
    'Cache hit rate percentage'
)

queue_size = Gauge(
    'queue_size',
    'Current queue size',
    ['queue_name']
)

error_count = Counter(
    'application_errors_total',
    'Total application errors',
    ['error_type']
)

def track_metrics(f):
    @wraps(f)
    def decorated_function(*args, **kwargs):
        endpoint = request.endpoint or 'unknown'
        method = request.method
        
        active_requests.labels(method=method, endpoint=endpoint).inc()
        
        start_time = time.time()
        
        try:
            response = f(*args, **kwargs)
            status = response[1] if isinstance(response, tuple) else 200
            
            request_count.labels(
                method=method,
                endpoint=endpoint,
                status=status
            ).inc()
            
            return response
            
        except Exception as e:
            error_count.labels(error_type=type(e).__name__).inc()
            request_count.labels(
                method=method,
                endpoint=endpoint,
                status=500
            ).inc()
            raise
            
        finally:
            duration = time.time() - start_time
            request_latency.labels(
                method=method,
                endpoint=endpoint
            ).observe(duration)
            
            active_requests.labels(method=method, endpoint=endpoint).dec()
    
    return decorated_function

@app.route('/metrics')
def metrics():
    return '', 403

@app.route('/')
@track_metrics
def index():
    return jsonify({'message': 'Welcome to the Flask Prometheus Demo'}), 200

@app.route('/api/users', methods=['GET'])
@track_metrics
def get_users():
    active_users.set(random.randint(50, 200))
    database_connections.set(random.randint(5, 20))
    
    return jsonify({
        'users': [
            {'id': 1, 'name': 'Alice'},
            {'id': 2, 'name': 'Bob'},
            {'id': 3, 'name': 'Charlie'}
        ]
    }), 200

@app.route('/api/transaction', methods=['POST'])
@track_metrics
def create_transaction():
    data = request.get_json() or {}
    transaction_type = data.get('type', 'purchase')
    amount = data.get('amount', 0)
    currency = data.get('currency', 'USD')
    
    success = random.choice([True, True, True, False])
    
    if success:
        business_transactions.labels(
            transaction_type=transaction_type,
            status='success'
        ).inc()
        business_revenue.labels(currency=currency).inc(amount)
        
        return jsonify({
            'status': 'success',
            'transaction_id': random.randint(1000, 9999)
        }), 201
    else:
        business_transactions.labels(
            transaction_type=transaction_type,
            status='failed'
        ).inc()
        error_count.labels(error_type='TransactionError').inc()
        
        return jsonify({
            'status': 'failed',
            'error': 'Transaction processing failed'
        }), 400

